import sys
import math
from collections import defaultdict

def is_square(x):
    if x == 0:
        return True
    s = int(math.isqrt(x))
    return s * s == x

def main():
    input = sys.stdin.read
    data = input().split()
    N = int(data[0])
    A = list(map(int, data[1:]))

    square_count = defaultdict(int)
    count = 0

    for num in A:
        if num == 0:
            count += square_count[num]
            square_count[num] += 1
        else:
            root = int(math.isqrt(num))
            if root * root == num:
                count += square_count[num]
                square_count[num] += 1
            else:
                square_free = num
                while square_free > 1 and int(math.isqrt(square_free)) ** 2 == square_free:
                    square_free //= int(math.isqrt(square_free)) ** 2
                square_count[square_free] += 1

    print(count)

if __name__ == "__main__":
    main()
